parameters.jsCode:
const edges = $json?.data?.posts?.edges || [];

return edges.map(edge => {
  const node = edge?.node || {};

  return {
    json: {
      title: node.name || "",
      source: "ProductHunt",
      summary: node.tagline || node.description || "",
      url: node.url || "",
      published_date: node.createdAt || "",
      created_at: new Date().toISOString(),
      status: "New"
    }
  };
});

const repos = $json.items || [];

return repos.map(repo => {
  return {
    json: {
      title: repo.name,
      source: "GitHub",
      summary: repo.description || "",
      url: repo.html_url,
      published_date: repo.created_at,
      created_at: new Date().toISOString(),
      status: "New"
    }
  };
});

const feed = $json.feed || $json;
let entries = feed.entry || [];

if (!Array.isArray(entries)) {
  entries = [entries];
}

return entries.map(entry => {
  const title = entry.title?._text || entry.title || "";
  const summary = entry.summary?._text || entry.summary || "";
  const published = entry.published?._text || entry.published || "";
  const url = entry.id?._text || entry.id || "";

  return {
    json: {
      title: String(title).replace(/\s+/g, " ").trim(),
      source: "arXiv",
      summary: String(summary).replace(/\s+/g, " ").trim().slice(0, 500),
      url: String(url),
      published_date: String(published),
      created_at: new Date().toISOString(),
      status: "New"
    }
  };
});

const items = $input.all();

const keywords = [
  "ai", "artificial intelligence", "llm", "gpt",
  "agent", "agents", "rag", "multimodal",
  "model", "models", "machine learning", "ml",
  "genai", "generative", "embedding",
  "fine-tuning", "inference", "vision", "voice"
];

function scoreItem(item) {
  const title = (item.json.title || "").toLowerCase();
  const summary = (item.json.summary || "").toLowerCase();
  const text = `${title} ${summary}`;

  let score = 0;
  for (const k of keywords) {
    if (text.includes(k)) score += 2;
  }

  const source = item.json.source || "";
  if (source === "ProductHunt") score += 3;
  if (source === "GitHub") score += 2;
  if (source === "arXiv") score += 2;
  if (source === "HackerNews") score += 1;

  return score;
}

const seen = new Set();
const deduped = items.filter(item => {
  const url = item.json.url || "";
  if (!url) return true;
  if (seen.has(url)) return false;
  seen.add(url);
  return true;
});

const relevant = deduped.filter(item => {
  const title = (item.json.title || "").toLowerCase();
  const summary = (item.json.summary || "").toLowerCase();
  const text = `${title} ${summary}`;
  return keywords.some(k => text.includes(k));
});

const groups = {
  ProductHunt: [],
  GitHub: [],
  arXiv: [],
  HackerNews: []
};

for (const item of relevant) {
  const source = item.json.source || "";
  if (groups[source]) {
    groups[source].push({ item, score: scoreItem(item) });
  }
}

for (const source of Object.keys(groups)) {
  groups[source].sort((a, b) => b.score - a.score);
}

const limits = {
  ProductHunt: 3,
  GitHub: 2,
  arXiv: 2,
  HackerNews: 1
};

let selected = [];

for (const source of Object.keys(limits)) {
  selected.push(...groups[source].slice(0, limits[source]).map(x => x.item));
}

if (selected.length < 8) {
  const selectedUrls = new Set(selected.map(x => x.json.url || ""));
  const leftovers = [];

  for (const source of Object.keys(groups)) {
    for (const x of groups[source]) {
      const url = x.item.json.url || "";
      if (!selectedUrls.has(url)) leftovers.push(x);
    }
  }

  leftovers.sort((a, b) => b.score - a.score);

  for (const x of leftovers) {
    if (selected.length >= 8) break;
    selected.push(x.item);
  }
}

return selected;

function safeText(value, fallback = '') {
  const text = String(value ?? '').trim();
  return text || fallback;
}

function clampScore(value) {
  const n = Number(value);
  if (!Number.isFinite(n)) return 0;
  return Math.max(1, Math.min(10, Math.round(n)));
}

function hashText(text) {
  let hash = 5381;
  for (let i = 0; i < text.length; i++) {
    hash = ((hash << 5) + hash) + text.charCodeAt(i);
    hash = hash >>> 0;
  }
  return `h_${hash.toString(16)}`;
}

const aiRaw = (($json.choices?.[0]?.message?.content) || '{"category":"unknown","lab_relevance":0,"practicality":0,"novelty":0,"recommended_action":"Watch","why_it_matters":"Model response missing"}')
  .replace(/```json/g, '')
  .replace(/```/g, '')
  .replace(/^json\s*/i, '')
  .replace(/\n/g, ' ')
  .replace(/\\"/g, '"')
  .trim();

let parsed;
try {
  parsed = JSON.parse(aiRaw || '{}');
} catch (e) {
  parsed = {
    category: 'unknown',
    lab_relevance: 0,
    practicality: 0,
    novelty: 0,
    recommended_action: 'Watch',
    why_it_matters: 'Parsing failed'
  };
}

const original = $('Code in JavaScript2').item.json;
const lab = clampScore(parsed.lab_relevance);
const prac = clampScore(parsed.practicality);
const nov = clampScore(parsed.novelty);
const final_score = Number(((lab + prac + nov) / 3).toFixed(2));
const title = safeText(original.title, 'untitled');
const url = safeText(original.url, '');
const hash_id = hashText(`${title.toLowerCase()}|${url.toLowerCase()}`);
const batch_id = 'n8n-' + DateTime.now().toFormat('yyyyLLdd-HHmmss') + '-' + hash_id;

const tool = {
  id: hash_id,
  hash_id,
  title,
  source: safeText(original.source),
  summary: safeText(original.summary),
  url,
  published_date: safeText(original.published_date),
  created_at: safeText(original.created_at, new Date().toISOString()),
  status: safeText(original.status, 'New'),
  category: safeText(parsed.category, 'unknown'),
  lab_relevance: lab,
  practicality: prac,
  novelty: nov,
  final_score,
  recommended_action: safeText(parsed.recommended_action, 'Watch'),
  why_it_matters: safeText(parsed.why_it_matters, 'Pending').slice(0, 220)
};

const payload = {
  source: 'n8n.tools.feed',
  version: '1.0',
  generated_at: new Date().toISOString(),
  batch_id,
  data: [tool]
};

const rawBody = JSON.stringify(payload);
const timestamp = Math.floor(Date.now() / 1000).toString();

return [{ json: { payload, rawBody, timestamp } }];

const crypto = require('crypto');
const secret = $env.RADAR_INGEST_SECRET || 'replace-me';
const rawBody = $json.rawBody;
const signature = crypto.createHmac('sha256', secret).update(rawBody).digest('hex');
return [{ json: { payload: $json.payload, timestamp: $json.timestamp, signature } }];
